<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Sorting Visualizer</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #10131a;
      --panel: #191e28;
      --panel-2: #202735;
      --text: #e9eef7;
      --muted: #98a5b8;
      --accent: #5eead4;
      --accent-2: #60a5fa;
      --danger: #fb7185;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      background:
        radial-gradient(circle at top, #202a3a 0, transparent 42%),
        var(--bg);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      display: flex;
      justify-content: center;
      padding: 28px 18px;
    }

    .app {
      width: min(1100px, 100%);
    }

    header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 20px;
      margin-bottom: 20px;
    }

    h1 {
      margin: 0;
      font-size: clamp(1.5rem, 3vw, 2.25rem);
      letter-spacing: -0.04em;
    }

    .subtitle {
      margin: 6px 0 0;
      color: var(--muted);
      font-size: 0.95rem;
    }

    .controls {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      margin-bottom: 18px;
    }

    button {
      border: 1px solid #354156;
      border-radius: 9px;
      padding: 10px 17px;
      background: var(--panel-2);
      color: var(--text);
      font: inherit;
      font-weight: 650;
      cursor: pointer;
      transition: transform 0.15s ease, border-color 0.15s ease, background 0.15s ease;
    }

    button:hover {
      transform: translateY(-1px);
      border-color: var(--accent-2);
      background: #273247;
    }

    button:active {
      transform: translateY(0);
    }

    #sort {
      background: #164e63;
      border-color: #2dd4bf;
    }

    #sort:hover {
      background: #1d657e;
    }

    #bars {
      height: min(62vh, 530px);
      min-height: 280px;
      display: flex;
      align-items: flex-end;
      gap: 5px;
      padding: 24px 18px 18px;
      border: 1px solid #293446;
      border-radius: 14px;
      background: linear-gradient(180deg, rgba(31, 41, 55, 0.72), rgba(15, 23, 42, 0.92));
      box-shadow: 0 18px 50px rgba(0, 0, 0, 0.28);
      overflow: hidden;
    }

    .bar {
      flex: 1 1 0;
      min-width: 2px;
      min-height: 4px;
      border-radius: 5px 5px 2px 2px;
      background: linear-gradient(180deg, var(--accent), var(--accent-2));
      box-shadow: 0 0 12px rgba(94, 234, 212, 0.12);
      transition: height 55ms linear, background 100ms ease, opacity 100ms ease;
    }

    .bar.active {
      background: linear-gradient(180deg, #fcd34d, #f97316);
      box-shadow: 0 0 16px rgba(251, 191, 36, 0.35);
    }

    .status {
      margin-top: 12px;
      color: var(--muted);
      font-size: 0.88rem;
    }

    @media (max-width: 650px) {
      body {
        padding: 20px 10px;
      }

      header {
        display: block;
      }

      .controls {
        margin-top: 16px;
      }

      #bars {
        gap: 2px;
        padding-inline: 8px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header>
      <div>
        <h1>Sorting Visualizer</h1>
        <p class="subtitle">Watch a comparison sort arrange the bars in ascending order.</p>
      </div>
    </header>

    <div class="controls">
      <button id="sort" type="button">Sort</button>
      <button id="shuffle" type="button">Shuffle</button>
      <button id="reset" type="button">Reset</button>
    </div>

    <section id="bars" aria-label="Array visualization"></section>
    <div class="status" id="status">Ready</div>
  </main>

  <script>
    (function () {
      const barsElement = document.getElementById("bars");
      const statusElement = document.getElementById("status");
      const sortButton = document.getElementById("sort");
      const shuffleButton = document.getElementById("shuffle");
      const resetButton = document.getElementById("reset");

      const initialArray = [
        42, 78, 19, 93, 35, 61, 12, 86, 54, 27,
        70, 47, 100, 23, 66, 31, 89, 8, 57, 74,
        16, 50, 38, 82, 6, 96, 44, 68, 25, 59
      ];

      let values = initialArray.slice();
      let pass = 0;
      let index = 0;
      let swappedInPass = false;
      let finished = false;
      let animationId = null;
      let activePair = [];

      function isAscending() {
        for (let i = 1; i < values.length; i++) {
          if (values[i - 1] > values[i]) return false;
        }
        return true;
      }

      function resetSortState() {
        pass = 0;
        index = 0;
        swappedInPass = false;
        finished = values.length < 2;
        activePair = [];
      }

      function render() {
        barsElement.innerHTML = "";

        let maximum = 0;
        for (const value of values) {
          if (value > maximum) maximum = value;
        }

        for (let i = 0; i < values.length; i++) {
          const bar = document.createElement("div");
          bar.className = "bar";
          const value = Number(values[i]) || 0;
          const height = maximum > 0
            ? Math.max(4, (value / maximum) * 100)
            : 50;

          bar.style.height = height + "%";
          bar.title = String(values[i]);
          bar.setAttribute("aria-label", "Value " + values[i]);

          if (activePair.indexOf(i) !== -1) {
            bar.classList.add("active");
          }

          barsElement.appendChild(bar);
        }
      }

      function setStatus(message) {
        statusElement.textContent = message;
      }

      function sortStep() {
        if (finished) {
          activePair = [];
          render();
          return true;
        }

        const length = values.length;
        if (length < 2) {
          finished = true;
          activePair = [];
          render();
          return true;
        }

        activePair = [index, index + 1];

        if (values[index] > values[index + 1]) {
          const temporary = values[index];
          values[index] = values[index + 1];
          values[index + 1] = temporary;
          swappedInPass = true;
        }

        index++;

        if (index >= length - 1 - pass) {
          pass++;
          index = 0;

          if (!swappedInPass || pass >= length - 1) {
            finished = true;
          }

          swappedInPass = false;
        }

        render();

        if (finished) {
          activePair = [];
          render();
          setStatus("Sorted");
        } else {
          setStatus("Comparing elements");
        }

        return finished;
      }

      function cancelAnimation() {
        if (animationId !== null) {
          cancelAnimationFrame(animationId);
          animationId = null;
        }
      }

      function animateSort() {
        cancelAnimation();

        function frame() {
          const complete = sortStep();
          if (!complete) {
            animationId = requestAnimationFrame(frame);
          } else {
            animationId = null;
          }
        }

        frame();
      }

      function shuffleValues() {
        cancelAnimation();

        for (let i = values.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          const temporary = values[i];
          values[i] = values[j];
          values[j] = temporary;
        }

        resetSortState();
        render();
        setStatus("Shuffled");
      }

      function resetValues() {
        cancelAnimation();
        values = initialArray.slice();
        resetSortState();
        render();
        setStatus("Ready");
      }

      window.viz = {
        array: function () {
          return values.slice();
        },
        setArray: function (array) {
          cancelAnimation();
          values = Array.from(array, Number);
          resetSortState();
          render();
          setStatus("Custom array loaded");
        },
        sortStep: sortStep,
        sorted: isAscending
      };

      sortButton.addEventListener("click", animateSort);
      shuffleButton.addEventListener("click", shuffleValues);
      resetButton.addEventListener("click", resetValues);

      resetSortState();
      render();
    })();
  </script>
</body>
</html>
